$('#registerForm').submit(function(e) {
  e.preventDefault(); // ป้องกัน reload

  let isValid = true;
  const email = $('#email').val();
  const password = $('#password').val();

  // ตรวจสอบ Email
  if (!email.match(/^[\w-]+@[\w-]+\.[a-z]{2,}$/i)) {
    $('#emailError').text('รูปแบบ Email ไม่ถูกต้อง');
    isValid = false;
  }

  // ตรวจสอบ Password
  if (password.length < 8) {
    $('#passError').text('รหัสผ่านต้องมีอย่างน้อย 8 ตัวอักษร');
    isValid = false;
  }

  if (isValid) {
    $.post('/api/register', $(this).serialize())
     .done(function() { alert('สมัครสำเร็จ!'); });
  }
});

let page = 1;
let loading = false;

$(window).scroll(function() {
  // ถ้าเลื่อนถึงด้านล่าง
  if ($(window).scrollTop() + $(window).height() 
      >= $(document).height() - 100) {

    if (!loading) {
      loading = true;
      page++;

      $('#loader').show();

      $.getJSON('/api/posts?page=' + page, function(data) {
        $.each(data.posts, function(i, post) {
          $('#feed').append(
            '<article class="post">' +
            '<h3>' + post.title + '</h3>' +
            '<p>' + post.excerpt + '</p>' +
            '</article>'
          );
        });
        loading = false;
        $('#loader').hide();
      });
    }
  }
});

let searchTimer;

$('#searchInput').on('keyup', function() {
  const query = $(this).val().trim();

  // ใช้ debounce ป้องกันส่ง request มากเกินไป
  clearTimeout(searchTimer);

  if (query.length < 2) {
    $('#searchResults').empty();
    return;
  }

  searchTimer = setTimeout(function() {
    $.ajax({
      url: '/api/search',
      data: { q: query },
      beforeSend: function() {
        $('#searchResults').html(
          '<div class="loading">กำลังค้นหา...</div>'
        );
      },
      success: function(results) {
        let html = '';
        $.each(results, function(i, item) {
          html += '<div class="result-item">' +
                  '<strong>' + item.title + '</strong>' +
                  '<p>' + item.description + '</p>' +
                  '</div>';
        });
        $('#searchResults').html(html || 'ไม่พบผลลัพธ์');
      }
    });
  }, 300); // รอ 300ms หลังหยุดพิมพ์
});

const API = '/api/tasks';

// CREATE — สร้าง Task ใหม่
function createTask(title) {
  return $.post(API, { title: title, done: false });
}

// READ — อ่าน Tasks ทั้งหมด
function getTasks() {
  return $.getJSON(API);
}

// UPDATE — อัปเดต Task
function updateTask(id, data) {
  return $.ajax({
    url: API + '/' + id,
    type: 'PUT',
    data: JSON.stringify(data),
    contentType: 'application/json'
  });
}

// DELETE — ลบ Task
function deleteTask(id) {
  return $.ajax({
    url: API + '/' + id,
    type: 'DELETE'
  });
}

