$('#uploadForm').submit(function(e) {
  e.preventDefault();

  const formData = new FormData(this);

  $.ajax({
    url: '/api/upload',
    type: 'POST',
    data: formData,
    processData: false,  // ห้าม jQuery แปลง data
    contentType: false,  // ให้ browser ตั้ง content-type
    xhr: function() {
      const xhr = new XMLHttpRequest();

      // ติดตาม Upload Progress
      xhr.upload.addEventListener('progress', function(e) {
        if (e.lengthComputable) {
          const percent = (e.loaded / e.total) * 100;
          $('#progressBar')
            .css('width', percent + '%')
            .text(Math.round(percent) + '%');
        }
      });

      return xhr;
    },
    success: function(response) {
      $('#status').html('✅ อัปโหลดสำเร็จ!');
    }
  });
});

